local G = DYCLegendary local lootSystem = G.lootSystem local require = G.DYCModRequire local enchantmentSystem = require( "dyc_enchantments" ) local enchantmentList = enchantmentSystem.list local monsterEncTable = { "woundeddamage" , "sanitydrain_1c25" , "poisoner_c20" , "criticalstrike_200c20" , "sanitydrain_monster" , "rebounddamage_monster" , "lifesteal_weakboss" , "icebody_c10" , "firebody_c10" , "poisonbody_monster" , "damage_5" , "damage_10" , "damage_15" , "damage_20" , "damage_monster" , "disarm_monster" , "maxhealth_monster" , "maxhealth_monster2" , "recover_monster" , "speed_monster" , "cripple_monster" , "stickybody_monster" , "weaken_monster" ,} local bossEncTable = { "woundeddamage" , "damage_weakboss" , "sanitydrain_weakboss" , "freezer_c20" , "poisoner_c20" , "igniter_c20" , "icebody_c20" , "firebody_c20" , "firebody_boss" , "rebounddamage_weakboss" , "lifesteal_weakboss" , "laserbeam" , "bladeofwind" , "disarm_boss" , "maxhealth_boss" , "recover_boss" , "speed_boss" , "stickybody_boss" , "weaken_weakboss" ,} local bossEncTable2 = { "woundeddamage" , "sanitydrain_boss" , "healthdrain_boss" , "criticalstrike_boss" , "rebounddamage_boss" , "poisoner_boss" , "freezer_boss" , "igniter_boss" , "damage_boss" , "lifesteal_boss" , "icebody_boss" , "firebody_boss" , "bladeofwind_boss" , "laserbeam_boss" , "damagereduction_boss" , "maxhealth_boss" , "recover_boss" , "shadowshield_boss" , "sacreddefense" , "fireturret_boss" , "iceturret_boss" , "frostzone_boss" , "cripple_boss" , "speed_boss" , "stickybody_boss" , "weaken_boss" , "phantomassault_boss" ,} local function CanEnhanceMonster(inst) return inst:HasTag( "hostile" ) or inst:HasTag( "monster" ) or inst:HasTag( "largecreature" ) or inst:HasTag( "pig" ) or inst:HasTag( "manrabbit" ) end local function GetDays() return G.gameData:GetDays() end local function GetEnhancedEnc(name, lv) local newName = name.."_tweaklv"..lv if enchantmentList[newName] then return newName end return name end local function DYCAnyPost(inst) if G.cfgs.mobtweak then local level = G.cfgs.mobtweaklevel or 0x2 local combat = inst.components.combat local defaultdamage = combat and combat.defaultdamage defaultdamage = defaultdamage or 0x0 if inst.prefab and (inst.prefab == "pigman_royalguard" or inst.prefab == "pigman_royalguard_2" ) then inst:ListenForEvent( "itemget" , function(inst, data) local item = data.item local itemWeapon = item and item.components.weapon local isNotTorch = item and item.prefab and item.prefab ~= "torch" if isNotTorch and itemWeapon and not item.dycQuality then item:SetRandomQuality() for i = 0x1, 0x3 do if math.random() < 0.3 then item:AddEnchantment(lootSystem:GetEnchantment(item), true) end end end end) inst:DoTaskInTime(0x0, function() if not inst.dycQuality then inst:SetRandomQuality() local days = GetDays() local interval = level <= 0x1 and 0x28 or level >= 0x4 and 0xe or level >= 0x3 and 0x14 or 0x1e local maxNum = (level <= 0x1 and 0x3 or level >= 0x4 and 0x9 or level >= 0x3 and 0x7 or 0x5) - 0x1 local num = math.max(0x0, math.min(math.floor(days / interval), maxNum)) + 0x1 inst.dycNoEncPrint = true for i = 0x1, num do local enc = nil local try = 0x0 while enc == nil and try < 0x32 do local name = GetEnhancedEnc(monsterEncTable[math.random(#monsterEncTable)], level) enc = inst:AddEnchantment(name, true) try = try + 0x1 end end if level == 0x3 then inst:AddEnchantment( "maxhealth_monster_lv3" ) elseif level == 0x4 then inst:AddEnchantment( "maxhealth_monster_lv4" ) end inst.dycNoEncPrint = nil end end) elseif lootSystem:IsWeakBoss(inst) then inst:DoTaskInTime(0x0, function() if not inst.dycQuality then inst:SetRandomQuality() local days = GetDays() local interval = level <= 0x1 and 0x28 or level >= 0x4 and 0xe or level >= 0x3 and 0x14 or 0x1e local maxNum = level <= 0x1 and 0x4 or level >= 0x4 and 0xc or level >= 0x3 and 0x8 or 0x6 local num = math.max(0x0, math.min(math.floor(days / interval), maxNum)) inst.dycNoEncPrint = true for i = 0x1, num do local enc = nil local try = 0x0 while enc == nil and try < 0x32 do local name = GetEnhancedEnc(bossEncTable[math.random(#bossEncTable)], level) enc = inst:AddEnchantment(name, true) try = try + 0x1 end end if level == 0x3 then inst:AddEnchantment( "maxhealth_weakboss_lv3" ) elseif level == 0x4 then inst:AddEnchantment( "maxhealth_weakboss_lv4" ) end inst.dycNoEncPrint = nil end end) elseif lootSystem:IsStrongBoss(inst) then inst:DoTaskInTime(0x0, function() if not inst.dycQuality then inst:SetRandomQuality() local days = GetDays() local interval = level <= 0x1 and 0x28 or level >= 0x4 and 0xe or level >= 0x3 and 0x14 or 0x1e local maxNum = level <= 0x1 and 0x4 or level >= 0x4 and 0xc or level >= 0x3 and 0x8 or 0x6 local num = math.max(0x0, math.min(math.floor(days / interval), maxNum)) inst.dycNoEncPrint = true for i = 0x1, num do local enc = nil local try = 0x0 while enc == nil and try < 0x32 do local name = GetEnhancedEnc(bossEncTable2[math.random(#bossEncTable2)], level) enc = inst:AddEnchantment(name, true) try = try + 0x1 end end if level == 0x3 then inst:AddEnchantment( "maxhealth_boss_lv3" ) elseif level == 0x4 then inst:AddEnchantment( "maxhealth_boss_lv4" ) end inst.dycNoEncPrint = nil end end) elseif defaultdamage > 0x0 and not inst:HasTag( "player" ) and CanEnhanceMonster(inst) then inst:DoTaskInTime(0x0, function() if not inst.dycQuality then inst:SetRandomQuality() local days = GetDays() local interval = level <= 0x1 and 0x28 or level >= 0x4 and 0xe or level >= 0x3 and 0x14 or 0x1e local maxNum = (level <= 0x1 and 0x3 or level >= 0x4 and 0x9 or level >= 0x3 and 0x7 or 0x5) - 0x1 local num = math.max(0x0, math.min(math.floor(days / interval), maxNum)) + 0x1 inst.dycNoEncPrint = true for i = 0x1, num do local enc = nil local try = 0x0 while enc == nil and try < 0x32 do local name = GetEnhancedEnc(monsterEncTable[math.random(#monsterEncTable)], level) enc = inst:AddEnchantment(name, true) try = try + 0x1 end end if level == 0x3 then inst:AddEnchantment( "maxhealth_monster_lv3" ) elseif level == 0x4 then inst:AddEnchantment( "maxhealth_monster_lv4" ) end inst.dycNoEncPrint = nil end end) end end end return DYCAnyPost 